var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"엇차, 그럼 여기서 잠시 머리 좀 식히고 계세요. 실비아 양.","JPN":"それではシルビアさん、ここで少し頭を冷やしてくださいね。","ENG":"There! Now, you can stay here and cool off, Sylvia.","TWN":"呃啊，您就在這裡好好冷靜一下吧，希爾維亞小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"실비아 양을 어떻게 할지 결정되는 대로 다시 돌아올 테니까요.","JPN":"シルビアさんをどうするかが決まったら、また戻ってきますので。","ENG":"We'll be back when we decide what to do with you.","TWN":"至於要怎麼處置妳，等我們決定之後再回來告訴妳。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"읍읍......!!","JPN":"うっうっ……！？","ENG":"Mmff! Mff!","TWN":"唔唔……！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그럼 가시죠, 서윤 양.","JPN":"アオイさん、行きましょう。","ENG":"Let's go, Seo Yoon.","TWN":"我們走吧，徐芸小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"서윤 양?","JPN":"アオイさん？","ENG":"Seo Yoon?","TWN":"徐芸小姐？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"나가기 전에 나 선배에게 한 가지 물어볼 게 있어.","JPN":"出て行く前に先輩に一つ聞きたいことがあるの。","ENG":"Before we leave, I want to ask you something.","TWN":"出去之前，我有個問題要問你。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"네? 그게 뭔가요?","JPN":"はい？　何でしょうか？","ENG":"Sure, what is it?","TWN":"嗯？什麼問題？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"조금 전에는 그냥 넘어갔는데 말이야......","JPN":"さっきは言わなかったけどさ……","ENG":"I didn't say this earlier, but...","TWN":"剛剛我雖然沒有多說什麼……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"나와 선배가 계속 같이 붙어 있었던 건 아니지 않아?","JPN":"私と先輩、ずっと一緒にいたわけじゃないでしょ？","ENG":"You and I weren't together the whole time.","TWN":"但是前輩你和我並不是一直在一起的不是嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"......무슨 말씀이시죠?","JPN":"……どういう意味ですか？","ENG":"What do you mean?","TWN":"……妳是說？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"사람들이 다시 모이길 기다리고 있을 때 선배가 옷에 커피를 쏟았잖아.","JPN":"みんなが集まるのを待ってるとき、先輩が服にコーヒーをこぼしたじゃない。","ENG":"While we were waiting for the others, you spilled coffee on your clothes.","TWN":"大家都在各自房裡等待的時候，你不小心把咖啡灑在了衣服上。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그리고는 얼룩을 지운다고 화장실에 다녀왔지.","JPN":"それで染みを落としてくるってトイレに行った。","ENG":"And you said you were going to go to the bathroom to remove the stains.","TWN":"然後就去了洗手間。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"몇 분밖에 안 되지만, 분명 그 시간만큼은 난 선배와 같이 있지 않았어.","JPN":"数分だったけど、その時間は私たち一緒にいなかったでしょ？","ENG":"That took only a few minutes, but still I wasn't with you during that time.","TWN":"雖然只有短短的幾分鐘，但那段時間你和我確實不在一起。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"호오, 과연...... 그런 일이 있었던 것 같기도 하군요.","JPN":"ほぉ、確かに……そんなことがあったようななかったような。","ENG":"Ah, right... I may have done that, yes.","TWN":"噢，是嗎……好像有那麼回事。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그런데 어째서 지금 그걸 말씀하시는 거죠?","JPN":"しかし、なぜ今それを？","ENG":"But why didn't you say that earlier?","TWN":"可是你為什麼現在才說起那件事呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"서로 자기 알리바이를 이야기할 때 말했으면 됐을 텐데요.","JPN":"自分のアリバイについて話す時に、言えば良かったのではありませんか？","ENG":"You could have said that while we were proving our alibis.","TWN":"為什麼不在剛剛互相證實不在場證明的時候說。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"안 되지. 그러면 선배를 기다리던 나까지 의심받잖아.","JPN":"そしたら、先輩を待ってた私まで疑われるもの。","ENG":"I couldn't. It would have brought suspicion onto me as well.","TWN":"當然不行，一旦說了等著前輩的我也會遭到懷疑。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배가 자리를 비운 동안 나도 혼자 있던 건 사실이니까.","JPN":"だってその間、私も一人だったってことは事実だから。","ENG":"I was also alone while you were away.","TWN":"畢竟你不在的時候，我也是獨自一人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 나는 내가 범인이 아니라는 사실을 아주 잘 알거든.","JPN":"でも私は私が犯人じゃないっていう事実をよく知っている。","ENG":"But I know that I'm not the perpetrator.","TWN":"不過，我很清楚我不是兇手。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 선배는 어떨까?","JPN":"それじゃ、先輩は？","ENG":"What about you, Shiyoon?","TWN":"那你呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하. 설마 절 의심하시는 건가요?","JPN":"ハハ、まさか僕を疑っているんですか？","ENG":"Hah hah, you're not suspecting me of anything, are you?","TWN":"哈哈，妳這是在懷疑我？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그래도 같은 회사에서 일하는 동료인데 조금 섭섭한걸요.","JPN":"これでも同じ会社で働く同僚だというのに、悲しいですね。","ENG":"We're coworkers. I thought you knew me better than that.","TWN":"我們可是同一間公司的同事，妳的懷疑讓我感到很遺憾。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"몰랐어? 내 취미가 원래 모든 사람을 의심하는 거거든.","JPN":"知らなかった？　私の趣味はすべての人間を疑うことなの。","ENG":"In case you didn't know, I'm suspicious of everyone. It's just in my nature.","TWN":"我的興趣就是懷疑每一個人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"더구나 처음 카일 씨가 날뛰기 직전에도 선배는 어디론가 사라져 버렸잖아?","JPN":"それに、カイルさんが暴れ出す直前にも先輩はそこにいなかったでしょ？","ENG":"Also, you disappeared just before Kyle started going on a rampage.","TWN":"而且凱爾發瘋的時候，前輩你剛好也不在。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"의심스러운 일이 한 번이면 몰라도 두 번이 되면 얘기가 조금 달라지지.","JPN":"怪しい行動が二回も重なったら、これは偶然なんかじゃない。","ENG":"When something suspicious happens not just once, but twice, you can't help but notice.","TWN":"一次不算什麼，但現在接二連三地出現可疑點，那就不同了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하, 장난이 지나치세요.","JPN":"ハハ、冗談が過ぎますよ。","ENG":"Hah hah. You're so funny.","TWN":"哈哈，妳別開玩笑了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"설령 그렇다고 하더라도 제가 범인이라는 증거는 없잖아요?","JPN":"もしそうだとしても、僕が犯人だという証拠はどこにあるんですか？","ENG":"But even if I did, there's no proof that I'm the perpetrator.","TWN":"哪怕真是如此，但妳也沒有證據證明我就是兇手啊？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"증거라......","JPN":"証拠ね……","ENG":"Proof...","TWN":"證據……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배, 옷에 흘린 커피 자국. 그대로 남아 있는걸.","JPN":"先輩、服にこぼしたコーヒーの染み。そのままなんじゃない？","ENG":"Shiyoon, you still have the coffee stains on your clothes.","TWN":"前輩，你身上殘留的咖啡漬就是證據。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하, 이것 참. 이래서 눈치 빠른 분은 상대하기 피곤하다니까요.","JPN":"ハハ、まったく。これだから勘の鋭い方を相手にするのは疲れるんです。","ENG":"Hah hah, wow! I have to say, you're way too shrewd for your own good.","TWN":"哈哈，真是的，所以說眼尖的對手很是讓人疲倦。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"평소처럼 그냥 모른 척 넘어가면 좋았을 텐데, 어쩔 수 없죠.","JPN":"いつものように見て見ぬ振りをすれば良いものを、仕方ありませんね。","ENG":"You should have feigned ignorance, like you usually do.","TWN":"妳就像平時那般睜一眼閉一眼多好啊，現在沒辦法了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"성야의 저주 속에 들어오신 걸 환영합니다.","JPN":"では改めて、聖夜の呪いの山荘へようこそ、","ENG":"Welcome to the Curse of the Holy Night.","TWN":"歡迎妳來到星夜的詛咒裡。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_10"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"서윤 양.","JPN":"アオイさん。","ENG":"Seo Yoon.","TWN":"徐芸小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};